```java
import java.util.*;

public class Solution {
    public static long[] solve(String[] words) {
        int n = words.length;
        if (n == 0) return new long[0];

        int[] lcp = new int[n - 1];
        for (int i = 0; i < n - 1; i++) {
            lcp[i] = lcpLength(words[i], words[i + 1]);
        }

        int[] prefix_max = new int[n - 1];
        prefix_max[0] = lcp[0];
        for (int i = 1; i < n - 1; i++) {
            prefix_max[i] = Math.max(prefix_max[i - 1], lcp[i]);
        }

        int[] suffix_max = new int[n - 1];
        suffix_max[n - 2] = lcp[n - 2];
        for (int i = n - 3; i >= 0; i--) {
            suffix_max[i] = Math.max(suffix_max[i + 1], lcp[i]);
        }

        long[] answer = new long[n];
        for (int i = 0; i < n; i++) {
            int left_max = 0;
            int right_max = 0;
            if (i - 2 >= 0) {
                left_max = prefix_max[i - 2];
            }
            if (i + 1 <= n - 2) {
                right_max = suffix_max[i + 1];
            }
            int new_pair = 0;
            if (i > 0 && i < n - 1) {
                new_pair = lcpLength(words[i - 1], words[i + 1]);
            }
            answer[i] = Math.max(Math.max(left_max, right_max), new_pair);
        }

        return answer;
    }

    private static int lcpLength(String a, String b) {
        int len = 0;
        while (len < a.length() && len < b.length() && a.charAt(len) == b.charAt(len)) {
            len++;
        }
        return len;
    }
}
```

